// Helper function to generate card image URLs
export function getCardImageUrl(card) {
  if (!card || !card.character) return null;

  const characterSlug = card.character
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');

  const raritySlug = (card.rarity || 'core')
    .toLowerCase()
    .replace(/\s+/g, '');

  return `/textures/${characterSlug}-${raritySlug}.png`;
}

// Fallback for when image fails to load
export function getCardFallbackImage(card) {
  if (!card || !card.character) return '/textures/card-back.png';

  // Try the image field from metadata as fallback
  if (card.image) {
    return `/textures/${card.image}`;
  }

  return '/textures/default-card.png';
}
